return [{
  json: {
    requestType: 'password_reset',
    userEmail: 'employee@company.com',
    userName: 'Jane Employee',
    details: 'Forgot my password and cant login to Salesforce',
    urgency: 'high',
    system: 'Salesforce',
    timestamp: new Date().toISOString()
  }
}];

const request = $input.first().json;

// Classify request type
const classifiers = {
  password_reset: {
    autoResolvable: true,
    riskLevel: 'low',
    action: 'generate_temp_password'
  },
  access_request: {
    autoResolvable: false,
    riskLevel: 'medium',
    action: 'request_manager_approval'
  },
  server_issue: {
    autoResolvable: false,
    riskLevel: 'high',
    action: 'escalate_immediately'
  },
  software_install: {
    autoResolvable: true,
    riskLevel: 'low',
    action: 'approve_standard_software'
  }
};

const classification = classifiers[request.requestType] || classifiers.access_request;

return [{
  json: {
    ...request,
    classification,
    canAutoResolve: classification.autoResolvable && request.urgency !== 'critical'
  }
}];

const req = $input.first().json;

// Simulate password reset
const tempPassword = 'TempPass' + Math.floor(Math.random() * 10000);

return [{
  json: {
    ...req,
    resolution: {
      action: 'password_reset',
      tempPassword: tempPassword,
      expiry: '24 hours',
      requiresChange: true
    }
  }
}];

